import type { MutableRefObject } from 'react';

import { canvasContainer } from './AnnotationsCanvasLayout.sty.js';
import { DisplayConfigContext } from './context/display-config.context.js';
import { AnnotationsChartDisplay } from './displays/AnnotationsChartDisplay.js';
import { Dimensions } from '../../../../types/dimensions.js';
import { Canvas } from '../../../canvas/Canvas.js';
import { CanvasContext } from '../../../canvas/CanvasContext.js';
import { CanvasShape } from '../../../canvas/types/canvas-shape.js';
import { useAnnotationsIconImages } from '../../hooks/useAnnotationsIconImages.js';

type AnnotationsCanvasLayoutProps = Dimensions;

export const AnnotationsCanvasLayout = ({
  height,
  width,
}: AnnotationsCanvasLayoutProps) => {
  const icons = useAnnotationsIconImages();
  const annotationsArea = { width, height, icons };

  return (
    <DisplayConfigContext.Provider value={{ annotationsArea }}>
      <div
        className={canvasContainer}
        style={{
          width,
          height,
          overflowY: 'hidden',
        }}
      >
        <CanvasContext.Provider
          value={{
            shapeRefs: new Map<string, MutableRefObject<CanvasShape>>(),
          }}
        >
          <Canvas width={width} height={height}>
            <AnnotationsChartDisplay />
          </Canvas>
        </CanvasContext.Provider>
      </div>
    </DisplayConfigContext.Provider>
  );
};

AnnotationsCanvasLayout['displayName'] = 'AnnotationsCanvasLayout';
